#ifndef GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_
#define GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include <torch/extension.h>
#include <cstdint>

#ifdef __CUDACC__
#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#endif

// Constants for this kernel specialization
constexpr int GQA_NUM_Q_HEADS = 32;
constexpr int GQA_NUM_KV_HEADS = 8;
constexpr int GQA_HEAD_DIM = 128;
constexpr int GQA_RATIO = GQA_NUM_Q_HEADS / GQA_NUM_KV_HEADS; // 4

// Kernel launch function declaration
void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const at::Tensor& q,          // [total_q, 32, 128], bfloat16, CUDA contiguous
    const at::Tensor& k,          // [total_kv, 8, 128], bfloat16, CUDA contiguous
    const at::Tensor& v,          // [total_kv, 8, 128], bfloat16, CUDA contiguous
    const at::Tensor& qo_indptr,  // [len_indptr], int32, CUDA or CPU (we'll ensure CUDA)
    const at::Tensor& kv_indptr,  // [len_indptr], int32, CUDA or CPU (we'll ensure CUDA)
    float sm_scale,               // softmax scale
    at::Tensor& output,           // [total_q, 32, 128], bfloat16, CUDA contiguous (out)
    at::Tensor& lse               // [total_q, 32], float32, CUDA contiguous (out)
);

// Host entry point bound to Python
std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::Tensor sm_scale  // scalar float32 tensor
);

#endif // GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <ATen/cuda/CUDAContext.h>
#include <cmath>
#include <cstdint>

#ifndef CUDA_CHECK
#define CUDA_CHECK(stmt)                                                     \
  do {                                                                       \
    cudaError_t err = stmt;                                                  \
    if (err != cudaSuccess) {                                                \
      printf("CUDA error %s at %s:%d: %s\n", #stmt, __FILE__, __LINE__,      \
             cudaGetErrorString(err));                                       \
    }                                                                        \
  } while (0)
#endif

// Utility: warp-wide sum reduction that returns the sum broadcast to all lanes
static inline __device__ float warp_sum_broadcast(float val) {
  unsigned mask = 0xffffffffu;
  for (int offset = 16; offset > 0; offset >>= 1) {
    val += __shfl_down_sync(mask, val, offset);
  }
  // Broadcast the result from lane 0 to all lanes
  val = __shfl_sync(mask, val, 0);
  return val;
}

static inline __device__ void load4_bf16_to_f32(const __nv_bfloat16* ptr, float out[4]) {
  // Load 4 contiguous bfloat16s as two __nv_bfloat162
  const __nv_bfloat162 v0 = *reinterpret_cast<const __nv_bfloat162*>(ptr);
  const __nv_bfloat162 v1 = *reinterpret_cast<const __nv_bfloat162*>(ptr + 2);
  float2 f0 = __bfloat1622float2(v0);
  float2 f1 = __bfloat1622float2(v1);
  out[0] = f0.x;
  out[1] = f0.y;
  out[2] = f1.x;
  out[3] = f1.y;
}

template<int HEAD_DIM, int NUM_QH, int NUM_KVH, int GQA, int WARPS_PER_BLOCK>
__launch_bounds__(WARPS_PER_BLOCK * 32, 2)
__global__ void gqa_ragged_prefill_kernel(
    const __nv_bfloat16* __restrict__ q,     // [total_q, NUM_QH, HEAD_DIM]
    const __nv_bfloat16* __restrict__ k,     // [total_kv, NUM_KVH, HEAD_DIM]
    const __nv_bfloat16* __restrict__ v,     // [total_kv, NUM_KVH, HEAD_DIM]
    const int32_t* __restrict__ qo_indptr,   // [len_indptr]
    const int32_t* __restrict__ kv_indptr,   // [len_indptr]
    const float sm_scale,
    __nv_bfloat16* __restrict__ out,         // [total_q, NUM_QH, HEAD_DIM]
    float* __restrict__ lse,                 // [total_q, NUM_QH]
    int len_indptr) {

  const int b = blockIdx.x;
  if (b >= len_indptr - 1) return;

  const int q_start = qo_indptr[b];
  const int q_end = qo_indptr[b + 1];
  const int kv_start = kv_indptr[b];
  const int kv_end = kv_indptr[b + 1];

  const int num_q_tokens = q_end - q_start;
  const int num_kv_tokens = kv_end - kv_start;
  const int delta = num_kv_tokens - num_q_tokens;

  if (num_q_tokens <= 0 || num_kv_tokens <= 0) {
    // Nothing to compute for this sequence, outputs were initialized by host
    return;
  }

  const int lane = threadIdx.x & 31;
  const int warp_id = threadIdx.x >> 5;

  // Each loop iteration processes one query token q_local and a tile of heads
  // We have 2 head tiles (since NUM_QH=32 and WARPS_PER_BLOCK may be 16)
  for (int q_local = 0; q_local < num_q_tokens; ++q_local) {
    // We process heads in tiles so each warp handles one head per tile
    #pragma unroll
    for (int head_tile = 0; head_tile < (NUM_QH + WARPS_PER_BLOCK - 1) / WARPS_PER_BLOCK; ++head_tile) {
      const int h = head_tile * WARPS_PER_BLOCK + warp_id;
      if (h >= NUM_QH) continue;

      const int kv_h = h / GQA; // map qo head to its kv head
      const int k_allowed = min(q_local + 1 + delta, num_kv_tokens);

      // Skip if no allowed KV tokens for this query (lse remains -inf, output zeros)
      if (k_allowed <= 0) {
        continue;
      }

      // Load Q vector for this (q, head) into registers, distributed across lanes
      const int q_index = q_start + q_local;
      const int d0 = lane * 4; // per-lane sub-dim start
      const long q_off = ((long)q_index * NUM_QH + h) * HEAD_DIM + d0;
      float q_reg[4];
      load4_bf16_to_f32(q + q_off, q_reg);

      // Online softmax accumulators
      float m = -CUDART_INF_F;  // running max
      float s = 0.0f;           // running sum exp(logits - m)
      float acc0 = 0.0f, acc1 = 0.0f, acc2 = 0.0f, acc3 = 0.0f; // accumulator for V contribution

      // Iterate over allowed KV keys
      for (int kv_i = 0; kv_i < k_allowed; ++kv_i) {
        const int kv_index = kv_start + kv_i;

        // Load K segment for (kv_index, kv_h) at dims d0..d0+3 and compute partial dot
        const long k_off = ((long)kv_index * NUM_KVH + kv_h) * HEAD_DIM + d0;
        float k_val[4];
        load4_bf16_to_f32(k + k_off, k_val);

        float partial = q_reg[0] * k_val[0]
                      + q_reg[1] * k_val[1]
                      + q_reg[2] * k_val[2]
                      + q_reg[3] * k_val[3];

        // Warp-reduce to get full dot product
        float x = warp_sum_broadcast(partial);
        // Scale by sm_scale (same across warp)
        x *= sm_scale;

        // Online softmax update (lane 0 computes, then broadcast)
        float w = 0.0f;
        float scale_old = 1.0f; // factor to scale previous accumulators when m increases
        if (lane == 0) {
          if (x > m) {
            // New max encountered
            float factor = (s > 0.f) ? __expf(m - x) : 0.0f;
            s = s * factor + 1.0f;
            m = x;
            scale_old = (s > 0.f && factor > 0.f) ? factor : factor; // as computed
            w = 1.0f; // exp(x - new_m) = 1
          } else {
            w = __expf(x - m);
            s += w;
            scale_old = 1.0f;
          }
        }
        // Broadcast w and scale_old to all lanes
        unsigned mask = 0xffffffffu;
        w = __shfl_sync(mask, w, 0);
        scale_old = __shfl_sync(mask, scale_old, 0);

        // Scale accumulators if m increased
        if (scale_old != 1.0f) {
          acc0 *= scale_old;
          acc1 *= scale_old;
          acc2 *= scale_old;
          acc3 *= scale_old;
        }

        // Load V segment and accumulate acc += w * V
        const long v_off = ((long)kv_index * NUM_KVH + kv_h) * HEAD_DIM + d0;
        float v_val[4];
        load4_bf16_to_f32(v + v_off, v_val);
        acc0 += w * v_val[0];
        acc1 += w * v_val[1];
        acc2 += w * v_val[2];
        acc3 += w * v_val[3];
      } // end for kv_i

      // Finalize: compute output = acc / s and write to global memory
      float inv_s = (s > 0.f) ? (1.0f / s) : 0.0f;
      __nv_bfloat16 o0 = __float2bfloat16(acc0 * inv_s);
      __nv_bfloat16 o1 = __float2bfloat16(acc1 * inv_s);
      __nv_bfloat16 o2 = __float2bfloat16(acc2 * inv_s);
      __nv_bfloat16 o3 = __float2bfloat16(acc3 * inv_s);

      const long out_off = ((long)q_index * NUM_QH + h) * HEAD_DIM + d0;
      // Store 4 bf16 values
      __nv_bfloat162 pack0 = __nvbfloat162(o0, o1);
      __nv_bfloat162 pack1 = __nvbfloat162(o2, o3);
      *reinterpret_cast<__nv_bfloat162*>(out + out_off) = pack0;
      *reinterpret_cast<__nv_bfloat162*>(out + out_off + 2) = pack1;

      // LSE base 2: (log(sum(exp(logits))) / ln(2)) == (log(s) + m) / ln(2)
      if (lane == 0) {
        float lse_val;
        if (s > 0.f) {
          constexpr float LOG2E_DEN = 0.69314718055994530942f; // ln(2)
          lse_val = (__logf(s) + m) / LOG2E_DEN;
        } else {
          lse_val = -CUDART_INF_F;
        }
        const long lse_off = (long)q_index * NUM_QH + h;
        lse[lse_off] = lse_val;
      }
    } // end head_tile
  } // end q_local
}

void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const at::Tensor& q,
    const at::Tensor& k,
    const at::Tensor& v,
    const at::Tensor& qo_indptr,
    const at::Tensor& kv_indptr,
    float sm_scale,
    at::Tensor& output,
    at::Tensor& lse) {

  const int len_indptr = qo_indptr.size(0);
  if (len_indptr <= 1) return;

  // Ensure tensors are CUDA and contiguous (assumed by caller)
  const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<at::BFloat16>());
  const __nv_bfloat16* k_ptr = reinterpret_cast<const __nv_bfloat16*>(k.data_ptr<at::BFloat16>());
  const __nv_bfloat16* v_ptr = reinterpret_cast<const __nv_bfloat16*>(v.data_ptr<at::BFloat16>());
  const int32_t* qo_ptr = qo_indptr.data_ptr<int32_t>();
  const int32_t* kv_ptr = kv_indptr.data_ptr<int32_t>();
  __nv_bfloat16* out_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());
  float* lse_ptr = lse.data_ptr<float>();

  const int blocks = len_indptr - 1;
  constexpr int WARPS_PER_BLOCK = 16;
  constexpr int THREADS = WARPS_PER_BLOCK * 32;

  cudaStream_t stream = at::cuda::getCurrentCUDAStream();

  gqa_ragged_prefill_kernel<GQA_HEAD_DIM, GQA_NUM_Q_HEADS, GQA_NUM_KV_HEADS, GQA_RATIO, WARPS_PER_BLOCK>
      <<<blocks, THREADS, 0, stream>>>(
          q_ptr, k_ptr, v_ptr,
          qo_ptr, kv_ptr,
          sm_scale,
          out_ptr, lse_ptr,
          len_indptr);

  CUDA_CHECK(cudaGetLastError());
}

#include "kernel.h"

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <vector>
#include <string>
#include <stdexcept>

#ifndef CUDA_CHECK
#define CUDA_CHECK(stmt)                                                     \
  do {                                                                       \
    cudaError_t err = stmt;                                                  \
    if (err != cudaSuccess) {                                                \
      throw std::runtime_error(std::string("CUDA error: ") +                 \
          cudaGetErrorString(err) + " at " + __FILE__ + ":" +                \
          std::to_string(__LINE__));                                         \
    }                                                                        \
  } while (0)
#endif

static inline void check_tensor_cuda_contig(const torch::Tensor& t, const std::string& name) {
  if (!t.device().is_cuda()) {
    throw std::invalid_argument(name + " must be a CUDA tensor");
  }
  if (!t.is_contiguous()) {
    throw std::invalid_argument(name + " must be contiguous");
  }
}

static inline void validate_shapes_and_dtypes(
    const torch::Tensor& q,
    const torch::Tensor& k,
    const torch::Tensor& v,
    const torch::Tensor& qo_indptr,
    const torch::Tensor& kv_indptr) {

  if (q.dtype() != torch::kBFloat16) throw std::invalid_argument("q must be bfloat16");
  if (k.dtype() != torch::kBFloat16) throw std::invalid_argument("k must be bfloat16");
  if (v.dtype() != torch::kBFloat16) throw std::invalid_argument("v must be bfloat16");
  if (qo_indptr.dtype() != torch::kInt32) throw std::invalid_argument("qo_indptr must be int32");
  if (kv_indptr.dtype() != torch::kInt32) throw std::invalid_argument("kv_indptr must be int32");

  if (q.dim() != 3 || k.dim() != 3 || v.dim() != 3) {
    throw std::invalid_argument("q, k, v must be 3D tensors");
  }
  if (q.size(1) != GQA_NUM_Q_HEADS || k.size(1) != GQA_NUM_KV_HEADS || v.size(1) != GQA_NUM_KV_HEADS) {
    throw std::invalid_argument("Head dimensions must be q:32 and k/v:8");
  }
  if (q.size(2) != GQA_HEAD_DIM || k.size(2) != GQA_HEAD_DIM || v.size(2) != GQA_HEAD_DIM) {
    throw std::invalid_argument("head_dim must be 128 for q, k, v");
  }

  if (qo_indptr.dim() != 1 || kv_indptr.dim() != 1) {
    throw std::invalid_argument("indptr tensors must be 1D");
  }
  if (qo_indptr.size(0) != kv_indptr.size(0)) {
    throw std::invalid_argument("qo_indptr and kv_indptr must have the same length");
  }

  // Constraints: total_q == qo_indptr[-1], total_kv == kv_indptr[-1]
  auto qo_cpu = qo_indptr.to(torch::kCPU);
  auto kv_cpu = kv_indptr.to(torch::kCPU);
  int32_t total_q_from_indptr = qo_cpu.data_ptr<int32_t>()[qo_cpu.size(0) - 1];
  int32_t total_kv_from_indptr = kv_cpu.data_ptr<int32_t>()[kv_cpu.size(0) - 1];

  if ((int64_t)total_q_from_indptr != q.size(0)) {
    throw std::invalid_argument("Constraint violation: total_q != qo_indptr[-1]");
  }
  if ((int64_t)total_kv_from_indptr != k.size(0) || (int64_t)total_kv_from_indptr != v.size(0)) {
    throw std::invalid_argument("Constraint violation: total_kv != kv_indptr[-1]");
  }
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::Tensor sm_scale_tensor) {

  // Validate devices and dtypes
  check_tensor_cuda_contig(q, "q");
  check_tensor_cuda_contig(k, "k");
  check_tensor_cuda_contig(v, "v");

  // indptr can be on CPU or GPU; move to GPU for kernel but also need CPU to validate lengths
  if (!qo_indptr.device().is_cuda()) qo_indptr = qo_indptr.to(q.device(), /*non_blocking*/false);
  if (!kv_indptr.device().is_cuda()) kv_indptr = kv_indptr.to(q.device(), /*non_blocking*/false);

  validate_shapes_and_dtypes(q, k, v, qo_indptr, kv_indptr);

  // Extract sm_scale scalar value
  if (sm_scale_tensor.scalar_type() != torch::kFloat32 || sm_scale_tensor.numel() != 1) {
    throw std::invalid_argument("sm_scale must be a scalar float32 tensor");
  }
  float sm_scale = sm_scale_tensor.item<float>();

  const int64_t total_q = q.size(0);
  const int64_t total_kv = k.size(0);
  const int64_t len_indptr = qo_indptr.size(0);

  // Allocate outputs on the same device as q
  auto options_bf16 = torch::TensorOptions().dtype(torch::kBFloat16).device(q.device());
  auto options_f32 = torch::TensorOptions().dtype(torch::kFloat32).device(q.device());

  torch::Tensor output = torch::zeros({total_q, GQA_NUM_Q_HEADS, GQA_HEAD_DIM}, options_bf16);
  // Initialize lse with -inf
  torch::Tensor lse = torch::full({total_q, GQA_NUM_Q_HEADS}, -std::numeric_limits<float>::infinity(), options_f32);

  // Ensure contiguous (should be already)
  q = q.contiguous();
  k = k.contiguous();
  v = v.contiguous();
  qo_indptr = qo_indptr.contiguous();
  kv_indptr = kv_indptr.contiguous();
  output = output.contiguous();
  lse = lse.contiguous();

  // Launch kernel
  launch_gqa_ragged_prefill_causal_h32_kv8_d128(
      q, k, v, qo_indptr, kv_indptr, sm_scale, output, lse);

  // Synchronize and check
  CUDA_CHECK(cudaGetLastError());
  CUDA_CHECK(cudaDeviceSynchronize());

  // Return results
  return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run,
        "gqa_ragged_prefill_causal_h32_kv8_d128 execution function",
        pybind11::arg("q"),
        pybind11::arg("k"),
        pybind11::arg("v"),
        pybind11::arg("qo_indptr"),
        pybind11::arg("kv_indptr"),
        pybind11::arg("sm_scale"));
}
